/// Fold icmp eq X, smin(smax(X, Lower), Upper) where Lower <= Upper.
/// This pattern checks if X is within the clamp range [Lower, Upper].
/// The result is true iff Lower <= X <= Upper.
/// This can be transformed to: ult (X - Lower), (Upper - Lower + 1)
static Instruction *foldICmpEqWithClamp(ICmpInst &I,
                                        InstCombiner::BuilderTy &Builder,
                                        const SimplifyQuery &SQ) {
  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);

  // Check for icmp eq
  if (I.getPredicate() != ICmpInst::ICMP_EQ)
    return nullptr;

  // Match pattern: icmp eq X, smin(smax(X, Lower), Upper)
  // OR: icmp eq smin(smax(X, Lower), Upper), X
  Value *X;
  const APInt *Lower, *Upper;

  bool Matched = false;

  // Try matching Op1 as the clamp: smin(smax(Op0, Lower), Upper)
  if (match(Op1, m_OneUse(m_Intrinsic<Intrinsic::smin>(
                     m_OneUse(m_Intrinsic<Intrinsic::smax>(
                         m_Specific(Op0), m_APInt(Lower))),
                     m_APInt(Upper))))) {
    X = Op0;
    Matched = true;
  }
  // Try matching Op0 as the clamp: smin(smax(Op1, Lower), Upper)
  else if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::smin>(
                       m_OneUse(m_Intrinsic<Intrinsic::smax>(
                           m_Specific(Op1), m_APInt(Lower))),
                       m_APInt(Upper))))) {
    X = Op1;
    Matched = true;
  }

  if (!Matched)
    return nullptr;

  // Check that Lower <= Upper for a valid clamp range
  if (Lower->sgt(*Upper))
    return nullptr;

  // Compute the transformed comparison:
  // X == clamp(X, Lower, Upper) is true iff Lower <= X <= Upper
  // This is equivalent to: 0 <= X - Lower <= Upper - Lower
  // Which can be checked as: ult (X - Lower), (Upper - Lower + 1)

  // Compute -Lower (the additive inverse)
  APInt NegLower = -(*Lower);
  Constant *NegLowerConst = ConstantInt::get(X->getType(), NegLower);

  // Try to simplify the add using simplifyAddInst, which handles
  // reassociation and constant folding
  Value *XMinusLower = simplifyAddInst(X, NegLowerConst,
                                       /*IsNSW=*/false, /*IsNUW=*/false, SQ);
  if (!XMinusLower) {
    // If simplification fails, create the add directly
    XMinusLower = Builder.CreateAdd(X, NegLowerConst);
  }

  // Compute (Upper - Lower + 1)
  APInt RangeWidth = *Upper - *Lower + 1;
  Value *RangeWidthVal = ConstantInt::get(X->getType(), RangeWidth);

  // Create ult (X - Lower), (Upper - Lower + 1)
  return new ICmpInst(ICmpInst::ICMP_ULT, XMinusLower, RangeWidthVal);
}
